%[text] # 배열 행렬 만들기
%[text] 이름: 최 병 조 
%[text] - 벡터와 행렬을 만드는 방법
%[text] - 행렬 연산
%[text] - 행렬의 일부
%[text] - 그래프
%[text] - 소리 파일 다루기 \
%%
%[text] ## 간단한 배열
%[text] - 벡터: 열벡터, 행벡터
%[text] - 행렬: 2차원 배열 \
 m = [1 4 2 5] % 행 벡터, row vector %[output:71cdb32b]
 v = [1; 6; -1; 3] % 열 벡터, column vector %[output:2c63a023]
 M = [1 3 5; 2 4 6] %[output:45b32f2a]
 m = M(2,2) %[output:2e2dd29e]
%%
%[text] ### 행렬의 크기
%[text] - 명령어: `size`, `length`, `numel` \
M %[output:7863edf4]
whos M %[output:9775add3]
[nRows, nCols] = size(M) %[output:2095a350] %[output:49c226f5]
nn = size(M, 2) %[output:20e39f84]
N = M' %[output:15f303a3]
ln = length(N) %[output:92410d51]
kk = numel(M) %[output:39ed46dc]
%%
%[text] ## 그래프
%[text] - 명령어: `plot`, `stem`, `bar` \
v %[output:6c419702]
h = plot(v, 'g-o', "MarkerFaceColor","r") %[output:873fc9b9] %[output:461e67c5]
h.LineWidth = 2; %[output:461e67c5]
grid on; %[output:461e67c5]
xlabel("$x$","Interpreter","latex");  %[output:461e67c5]
ylabel("y") %[output:461e67c5]
%%
%[text] stem 그래프
stem(v, 'r', 'filled'); %[output:94a7cb71]
grid; %[output:94a7cb71]
xlabel("value"); ylabel("measured") %[output:94a7cb71]
%%
%[text] bar 막대 그래프
bar(v, "FaceColor", "g") %[output:5a6e35e9]
legend("Income") %[output:5a6e35e9]
%%
%[text] ## 복소수 배열 / Complex Arrays
%[text] - 허수 / imaginary number
%[text] - $i = \\sqrt{-1}$ \
a = 2i + 1 %[output:66cebd7e]
aR = real(a), aImag = imag(a) %[output:70b8dcfa] %[output:194a1b9e]
b = [1 2i 2+1i -1] %[output:26f1e014]
b1 = b(1), b2 = b(2) %[output:4aa20a48] %[output:57e38a80]
b2 = b.^2 %[output:2540ee8e]
%%
%[text] ## Array Addressing
v = 10:-2:0 %[output:74cbb4e4]
v(1:2), v(end-1:end) %[output:8b16f26c] %[output:0d26f498]
v(1:2:end) %[output:3c7f9573]
u = v([2 4 1 3 6 5]) %[output:799a3f55]
M = magic(5) %[output:59cab344]
m = M(end, :) %[output:8feac32c]
w = M(:, 3) %[output:4e626d1c]
d = M(4:5, [2 4]) %[output:738ea28d]
v %[output:8dde3a8e]
v(10) = 8 %[output:40ad23e4]
%%
%[text] ### 배열을 만드는 또 다른 방법
q = (9:-2:3) + 1 %[output:23f60b5b]
r = linspace(0, 10, 6) %[output:119b79b9]
g = logspace(0, 4, 5) %[output:01404331]
b = 0:4, z = 2.^b %[output:252ad564] %[output:514506f0]
%%
%[text] ## 특별한 행렬
%[text] - `zeros`, `ones`, `magic`, `eye` \
U = zeros(3, 4)+ pi %[output:6edbfd4e]
Y = ones(2)*3 %[output:80a904f8]
M = magic(6) %[output:74841d7f]
dm = diag(diag(M)) %[output:55eb5d1e]
E = eye(3)*4 %[output:1fcd2b63]
E2 = E^2 %[output:2a65af98]

